import React from 'react';
import { CandidatePortrait } from '../shared/CandidatePortrait';

interface SupporterPortraitProps {
  photoUrl?: string | null;
  className?: string;
  containerClassName?: string;
  style?: React.CSSProperties;
}

export const SupporterPortrait = ({ photoUrl, className = '', containerClassName = '', style = {} }: SupporterPortraitProps) => {
  return (
    <div className={`bg-white overflow-hidden ${containerClassName}`} style={style}>
      {photoUrl ? (
        <img src={photoUrl} className={`w-full h-full object-cover ${className}`} />
      ) : (
        <div className="w-full h-full flex items-center justify-center bg-gray-50 text-gray-300">
          <span className="material-symbols-outlined font-light" style={{ fontSize: '8cqw' }}>person</span>
        </div>
      )}
    </div>
  );
};

export const TemplateCandidatePortrait = ({ className = '', containerClassName = '', style = {} }: { className?: string, containerClassName?: string, style?: React.CSSProperties }) => (
  <div className={`bg-white overflow-hidden ${containerClassName}`} style={style}>
     <CandidatePortrait className={`w-full h-full object-cover ${className}`} />
  </div>
);
